let sortOrder = true; // true for ascending, false for descending
let detailSortOrder = true; // 第二層排序順序

// 用於儲存展開的ETF代碼
let expandedETFs = new Set();

function renderETFs() {
    const tableBody = document.querySelector('#etf-table tbody');
    tableBody.innerHTML = ''; // 清空表格內容
    etfData.forEach(etf => {
        const row = document.createElement('tr');
        row.innerHTML = `
            <td>${etf.code}</td>
            <td>${etf.name}</td>
            <td>${etf.yield}</td>
        `;
        row.addEventListener('click', () => toggleDetails(etf.code));
        tableBody.appendChild(row);

        const detailsRow = document.createElement('tr');
        detailsRow.classList.add('details');
        detailsRow.style.display = expandedETFs.has(etf.code) ? 'table-row' : 'none'; // 根據展開狀態顯示
        detailsRow.innerHTML = `
            <td colspan="3">
                <table>
                    <thead>
                        <tr>
                            <th class="detail-sort" data-index="0">代號 <span class="sort-indicator">↑↓</span></th>
                            <th class="detail-sort" data-index="1">名稱 <span class="sort-indicator">↑↓</span></th>
                            <th class="detail-sort" data-index="2">佔比 <span class="sort-indicator">↑↓</span></th>
                            <th class="detail-sort" data-index="3">殖利率 <span class="sort-indicator">↑↓</span></th>
                        </tr>
                    </thead>
                    <tbody>
                        ${etf.details.map(detail => `
                            <tr>
                                <td>${detail.stockCode}</td>
                                <td>${detail.stockName}</td>
                                <td>${detail.ratio}</td>
                                <td>${detail.yield}</td>
                            </tr>
                        `).join('')}
                    </tbody>
                </table>
            </td>
        `;
        tableBody.appendChild(detailsRow);
    });
}

function toggleDetails(etfCode) {
    if (expandedETFs.has(etfCode)) {
        expandedETFs.delete(etfCode);
    } else {
        expandedETFs.add(etfCode);
    }
    renderETFs(); // 重新渲染表格
}

function sortTable(columnIndex) {
    etfData.sort((a, b) => {
        const aValue = String(Object.values(a)[columnIndex]); // 確保轉為字串
        const bValue = String(Object.values(b)[columnIndex]); // 確保轉為字串
        return sortOrder ? aValue.localeCompare(bValue) : bValue.localeCompare(aValue);
    });
    sortOrder = !sortOrder; // 切換排序順序
    renderETFs();
}

function sortDetailTable(details, columnIndex) {
    details.sort((a, b) => {
        const aValue = String(Object.values(a)[columnIndex]); // 確保轉為字串
        const bValue = String(Object.values(b)[columnIndex]); // 確保轉為字串
        return detailSortOrder ? aValue.localeCompare(bValue) : bValue.localeCompare(aValue);
    });
    detailSortOrder = !detailSortOrder; // 切換排序順序
}

document.querySelectorAll('th').forEach((th, index) => {
    th.addEventListener('click', () => sortTable(index));
});

// 為第二層表格的標題添加排序功能
document.addEventListener('click', (event) => {
    if (event.target.classList.contains('detail-sort')) {
        const th = event.target;
        const etfRow = th.closest('.details').previousElementSibling;
        const etfCode = etfRow.children[0].innerText; // 獲取ETF代碼
        const details = etfData.find(etf => etf.code === etfCode).details;
        const columnIndex = th.dataset.index;
        sortDetailTable(details, columnIndex);
        renderETFs(); // 重新渲染表格
    }
});

renderETFs();
